import {
  CopyObjectCommand,
  DeleteObjectsCommand,
  GetObjectCommand,
  ListObjectsV2Command,
  PutObjectCommand,
  S3Client,
  type _Object,
} from "@aws-sdk/client-s3";
import { pathToFileURL } from "node:url";

const SLUG_RE = /^[a-z0-9][a-z0-9-]*$/;
const RUN_ID_RE = /^[A-Za-z0-9][A-Za-z0-9._-]*$/;
const RESERVED_ROOT_FOLDERS = new Set([
  "agents",
  "events",
  "memory",
  "review",
  "skills",
]);
const GENERATED_BY =
  "Generated by repair-agent-workspace-blueprint from workspace-blueprint/START-HERE.md.";

export interface WorkspaceObject {
  key: string;
  etag?: string;
  size?: number;
  lastModified?: string;
}

export interface BlueprintSubAgent {
  slug: string;
  displayName: string;
  skillSlugs: string[];
}

export interface BlueprintModel {
  tenantSlug: string;
  agentSlug: string;
  rootSkillSlugs: string[];
  subAgents: BlueprintSubAgent[];
}

export interface RepairPlan {
  workspacePrefix: string;
  archivePrefix: string;
  reportKey: string;
  activeKeys: string[];
  archiveCopies: Array<{ sourceKey: string; targetKey: string }>;
  skillCopies: Array<{ sourceKey: string; targetKey: string }>;
  generatedFiles: Array<{ key: string; body: string; contentType: string }>;
  deleteKeys: string[];
  model: BlueprintModel;
}

export interface RepairSummary {
  dryRun: boolean;
  workspacePrefix: string;
  archivePrefix: string;
  reportKey: string;
  activeObjectCount: number;
  archiveCopyCount: number;
  skillCopyCount: number;
  generatedFileCount: number;
  deleteKeyCount: number;
  deletedActiveAgentsTree: boolean;
  model: BlueprintModel;
}

export interface WorkspaceBlueprintObjectStore {
  listObjects(prefix: string): Promise<WorkspaceObject[]>;
  getObjectText(key: string): Promise<string | null>;
  copyObject(sourceKey: string, targetKey: string): Promise<void>;
  putObject(key: string, body: string, contentType: string): Promise<void>;
  deleteObjects(keys: string[]): Promise<void>;
}

interface RepairInput {
  store: WorkspaceBlueprintObjectStore;
  tenantSlug: string;
  agentSlug: string;
  runId: string;
  dryRun?: boolean;
}

interface CliOptions {
  bucket: string;
  tenantSlug: string;
  agentSlug: string;
  runId: string;
  apply: boolean;
}

export function workspacePrefix(tenantSlug: string, agentSlug: string): string {
  assertSlug("tenant", tenantSlug);
  assertSlug("agent", agentSlug);
  return `tenants/${tenantSlug}/agents/${agentSlug}/workspace/`;
}

export function reportKey(agentSlug: string, runId: string): string {
  assertSlug("agent", agentSlug);
  assertRunId(runId);
  return `tenants/_ops/migrations/${agentSlug}-blueprint/${runId}.json`;
}

export function archivePrefix(
  tenantSlug: string,
  agentSlug: string,
  runId: string,
): string {
  assertSlug("tenant", tenantSlug);
  assertSlug("agent", agentSlug);
  assertRunId(runId);
  return `tenants/${tenantSlug}/agents/${agentSlug}/workspace-archives/blueprint-repair-${runId}/`;
}

export async function planWorkspaceBlueprintRepair({
  store,
  tenantSlug,
  agentSlug,
  runId,
}: RepairInput): Promise<RepairPlan> {
  const prefix = workspacePrefix(tenantSlug, agentSlug);
  const archivedAt = archivePrefix(tenantSlug, agentSlug, runId);
  const objects = await store.listObjects(prefix);
  const activeKeys = objects
    .map((object) => object.key)
    .filter((key) => key.startsWith(prefix) && !key.endsWith("/"))
    .sort();
  const relativeKeys = activeKeys.map((key) => key.slice(prefix.length));
  const model = await buildBlueprintModel({
    store,
    prefix,
    tenantSlug,
    agentSlug,
    relativeKeys,
  });

  const archiveCopies = activeKeys.map((sourceKey) => ({
    sourceKey,
    targetKey: `${archivedAt}${sourceKey.slice(prefix.length)}`,
  }));
  const skillCopies = planSubAgentSkillCopies(prefix, relativeKeys);
  const generatedFiles = [
    {
      key: `${prefix}AGENTS.md`,
      body: renderRootAgentsMd(model),
      contentType: "text/markdown",
    },
    {
      key: `${prefix}CONTEXT.md`,
      body: renderRootContextMd(model),
      contentType: "text/markdown",
    },
    ...model.subAgents.map((subAgent) => ({
      key: `${prefix}${subAgent.slug}/CONTEXT.md`,
      body: renderSubAgentContextMd(subAgent),
      contentType: "text/markdown",
    })),
  ];

  return {
    workspacePrefix: prefix,
    archivePrefix: archivedAt,
    reportKey: reportKey(agentSlug, runId),
    activeKeys,
    archiveCopies,
    skillCopies,
    generatedFiles,
    deleteKeys: activeKeys
      .filter((key) => key.slice(prefix.length).startsWith("agents/"))
      .sort(),
    model,
  };
}

export async function repairWorkspaceBlueprint(
  input: RepairInput,
): Promise<RepairSummary> {
  const plan = await planWorkspaceBlueprintRepair(input);
  const summary = repairSummary(plan, input.dryRun ?? true);
  const reportBody = JSON.stringify(
    {
      ...summary,
      generatedAt: new Date().toISOString(),
      generatedBy: GENERATED_BY,
      generatedFiles: plan.generatedFiles.map((file) =>
        file.key.slice(plan.workspacePrefix.length),
      ),
      deletedKeys: plan.deleteKeys.map((key) =>
        key.slice(plan.workspacePrefix.length),
      ),
      skillCopies: plan.skillCopies.map((copy) => ({
        from: copy.sourceKey.slice(plan.workspacePrefix.length),
        to: copy.targetKey.slice(plan.workspacePrefix.length),
      })),
    },
    null,
    2,
  );

  if (input.dryRun ?? true) {
    await input.store.putObject(plan.reportKey, reportBody, "application/json");
    return summary;
  }

  for (const copy of plan.archiveCopies) {
    await input.store.copyObject(copy.sourceKey, copy.targetKey);
  }
  for (const copy of plan.skillCopies) {
    await input.store.copyObject(copy.sourceKey, copy.targetKey);
  }
  for (const file of plan.generatedFiles) {
    await input.store.putObject(file.key, file.body, file.contentType);
  }
  await input.store.deleteObjects(plan.deleteKeys);
  await input.store.putObject(
    `${plan.workspacePrefix}manifest.json`,
    renderManifest(
      await input.store.listObjects(plan.workspacePrefix),
      plan.workspacePrefix,
    ),
    "application/json",
  );
  await input.store.putObject(plan.reportKey, reportBody, "application/json");
  return summary;
}

export function renderRootAgentsMd(model: BlueprintModel): string {
  const rows = model.subAgents
    .map(
      (subAgent) =>
        `| ${routingTask(subAgent)} | ${subAgent.slug}/ | ${subAgent.slug}/CONTEXT.md | ${formatList(subAgent.skillSlugs)} |`,
    )
    .join("\n");

  return trimFinalNewline(`# ${humanizeSlug(model.agentSlug)} Workspace Map

${GENERATED_BY}

## What This Is

This folder is the agent. Keep root files small and route work to scoped folders when a task needs a specialist workspace.

## Folder Structure

- AGENTS.md - always-loaded map and routing table.
- CONTEXT.md - root router for deciding what to load next.
- memory/ - primary agent memory.
- review/ and events/ - operational records; do not route task work here.
${model.subAgents
  .map(
    (subAgent) =>
      `- ${subAgent.slug}/ - ${subAgent.displayName} scoped workspace.`,
  )
  .join("\n")}

## Routing

| Task | Go to | Read | Skills |
| --- | --- | --- | --- |
${rows}

## Placement Rules

- Put new specialist context in a root folder named for that specialist.
- Put specialist-local skills under <folder>/skills/<skill-slug>/.
- Do not recreate agents/<slug>/; this workspace already uses folder-as-agent routing.
`);
}

export function renderRootContextMd(model: BlueprintModel): string {
  const routingRows = model.subAgents
    .map(
      (subAgent) =>
        `| ${routingTask(subAgent)} | ${subAgent.slug}/CONTEXT.md | ${formatList(subAgent.skillSlugs)} | Skip root-only memory unless the task needs primary-agent history. |`,
    )
    .join("\n");

  return trimFinalNewline(`# ${humanizeSlug(model.agentSlug)} Context Router

${GENERATED_BY}

## What This Is

Use this file after AGENTS.md to choose the smallest workspace that contains the context for the task.

## What To Load

| When the task is about... | Read next | Skills | Skip These |
| --- | --- | --- | --- |
| Root financial analysis, spreadsheet modeling, audits, or general artifact work | skills/<skill-slug>/SKILL.md as needed | ${formatList(model.rootSkillSlugs)} | Sub-agent folders unless a specialist is named. |
${routingRows}

## Process

1. Start with AGENTS.md for the folder map.
2. Use the table above to load exactly one scoped CONTEXT.md when a specialist is relevant.
3. Load local skill files only when their trigger matches the task.
4. Write new task artifacts in the folder whose CONTEXT.md you loaded.

## What Not To Do

- Do not load every folder by default.
- Do not put specialist work under agents/.
- Do not treat review/, events/, or manifest.json as task context.
`);
}

export function renderSubAgentContextMd(subAgent: BlueprintSubAgent): string {
  const skillRows = subAgent.skillSlugs
    .map(
      (skill) =>
        `| ${skill} | skills/${skill}/SKILL.md | Use when the task names or implies ${skill.replace(/-/g, " ")} work. |`,
    )
    .join("\n");

  return trimFinalNewline(`# ${subAgent.displayName} Workspace Context

${GENERATED_BY}

## What This Is

This is a scoped folder-as-agent workspace for ${subAgent.displayName}. Load it only when AGENTS.md or the root CONTEXT.md routes work here.

## What To Load

| Context | Read | Trigger |
| --- | --- | --- |
${skillRows || "| General scoped work | this CONTEXT.md | The task names this workspace. |"}

## Folder Structure

- CONTEXT.md - this router and scoped operating notes.

## Process

1. Use this folder as the working boundary for routed tasks.
2. Load one local skill at a time when its trigger matches.
3. Return cross-workspace handoffs through the root AGENTS.md routing table.

## What Not To Do

- Do not read sibling workspaces unless the root router says the task crosses scopes.
- Do not recreate copied root files here; root platform files stay at the workspace root.
`);
}

export function renderManifest(
  objects: WorkspaceObject[],
  prefix: string,
): string {
  const files = objects
    .filter((object) => object.key.startsWith(prefix))
    .map((object) => ({
      path: object.key.slice(prefix.length),
      etag: object.etag ?? "",
      size: object.size ?? 0,
      last_modified: object.lastModified ?? "",
    }))
    .filter((file) => file.path && file.path !== "manifest.json")
    .sort((left, right) => left.path.localeCompare(right.path));

  return JSON.stringify(
    {
      version: 1,
      generated_at: new Date().toISOString(),
      files,
    },
    null,
    2,
  );
}

async function buildBlueprintModel(input: {
  store: WorkspaceBlueprintObjectStore;
  prefix: string;
  tenantSlug: string;
  agentSlug: string;
  relativeKeys: string[];
}): Promise<BlueprintModel> {
  const rootSkillSlugs = skillSlugsFrom(
    input.relativeKeys,
    /^skills\/([^/]+)\//,
  );
  const subAgentSlugs = discoverSubAgentSlugs(input.relativeKeys);

  const subAgents: BlueprintSubAgent[] = [];
  for (const slug of subAgentSlugs) {
    const legacyContext = await input.store.getObjectText(
      `${input.prefix}agents/${slug}/CONTEXT.md`,
    );
    const rootContext = await input.store.getObjectText(
      `${input.prefix}${slug}/CONTEXT.md`,
    );
    subAgents.push({
      slug,
      displayName:
        parseDisplayName(legacyContext) ??
        parseDisplayName(rootContext) ??
        humanizeSlug(slug),
      skillSlugs: [
        ...new Set([
          ...skillSlugsFrom(
            input.relativeKeys,
            new RegExp(`^agents/${escapeRegExp(slug)}/skills/([^/]+)/`),
          ),
          ...skillSlugsFrom(
            input.relativeKeys,
            new RegExp(`^${escapeRegExp(slug)}/skills/([^/]+)/`),
          ),
        ]),
      ].sort(),
    });
  }

  return {
    tenantSlug: input.tenantSlug,
    agentSlug: input.agentSlug,
    rootSkillSlugs,
    subAgents,
  };
}

function discoverSubAgentSlugs(relativeKeys: string[]): string[] {
  return [
    ...new Set(
      relativeKeys
        .map((key) => {
          const legacy = /^agents\/([^/]+)\//.exec(key)?.[1];
          if (legacy) return legacy;
          const rootScoped = /^([^/]+)\/CONTEXT\.md$/.exec(key)?.[1];
          if (!rootScoped || RESERVED_ROOT_FOLDERS.has(rootScoped)) return null;
          return rootScoped;
        })
        .filter((slug): slug is string => Boolean(slug)),
    ),
  ].sort();
}

function planSubAgentSkillCopies(
  prefix: string,
  relativeKeys: string[],
): Array<{ sourceKey: string; targetKey: string }> {
  return relativeKeys
    .map((relativeKey) => {
      const match = /^agents\/([^/]+)\/skills\/(.+)$/.exec(relativeKey);
      if (!match) return null;
      const [, slug, skillPath] = match;
      return {
        sourceKey: `${prefix}${relativeKey}`,
        targetKey: `${prefix}${slug}/skills/${skillPath}`,
      };
    })
    .filter((copy): copy is { sourceKey: string; targetKey: string } =>
      Boolean(copy),
    )
    .sort((left, right) => left.targetKey.localeCompare(right.targetKey));
}

function repairSummary(plan: RepairPlan, dryRun: boolean): RepairSummary {
  return {
    dryRun,
    workspacePrefix: plan.workspacePrefix,
    archivePrefix: plan.archivePrefix,
    reportKey: plan.reportKey,
    activeObjectCount: plan.activeKeys.length,
    archiveCopyCount: plan.archiveCopies.length,
    skillCopyCount: plan.skillCopies.length,
    generatedFileCount: plan.generatedFiles.length,
    deleteKeyCount: plan.deleteKeys.length,
    deletedActiveAgentsTree: !dryRun && plan.deleteKeys.length > 0,
    model: plan.model,
  };
}

function skillSlugsFrom(relativeKeys: string[], pattern: RegExp): string[] {
  return [
    ...new Set(
      relativeKeys
        .map((key) => pattern.exec(key)?.[1])
        .filter((slug): slug is string => Boolean(slug) && slug !== ".gitkeep"),
    ),
  ].sort();
}

function routingTask(subAgent: BlueprintSubAgent): string {
  if (subAgent.skillSlugs.length === 0) {
    return `${subAgent.displayName} scoped work`;
  }
  return `${subAgent.displayName} ${subAgent.skillSlugs
    .map((skill) => skill.replace(/-/g, " "))
    .join(", ")}`;
}

function parseDisplayName(markdown: string | null): string | null {
  const source = markdown ?? "";
  const heading = /^#\s+(.+?)\s+(?:-|\u2014)\s+Context\s*$/m.exec(source);
  const workspaceHeading = /^#\s+(.+?)\s+Workspace Context\s*$/m.exec(source);
  return heading?.[1]?.trim() || workspaceHeading?.[1]?.trim() || null;
}

function humanizeSlug(slug: string): string {
  return slug
    .split("-")
    .filter((part) => Number.isNaN(Number(part)))
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
    .join(" ");
}

function formatList(values: string[]): string {
  return values.length > 0 ? values.join(", ") : "none";
}

function trimFinalNewline(markdown: string): string {
  return `${markdown.trim()}\n`;
}

function escapeRegExp(value: string): string {
  return value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function assertSlug(kind: string, slug: string): void {
  if (!SLUG_RE.test(slug)) {
    throw new Error(
      `Invalid ${kind} slug "${slug}". Expected ${SLUG_RE.source}.`,
    );
  }
}

function assertRunId(runId: string): void {
  if (!RUN_ID_RE.test(runId) || runId.includes("..")) {
    throw new Error(
      `Invalid run id "${runId}". Expected ${RUN_ID_RE.source} without '..'.`,
    );
  }
}

export class S3WorkspaceBlueprintObjectStore
  implements WorkspaceBlueprintObjectStore
{
  private readonly client: S3Client;
  private readonly bucket: string;

  constructor(input: { bucket: string; client?: S3Client }) {
    if (!input.bucket) throw new Error("S3 bucket is required");
    this.bucket = input.bucket;
    this.client =
      input.client ??
      new S3Client({
        region:
          process.env.AWS_REGION ||
          process.env.AWS_DEFAULT_REGION ||
          "us-east-1",
      });
  }

  async listObjects(prefix: string): Promise<WorkspaceObject[]> {
    const objects: WorkspaceObject[] = [];
    let ContinuationToken: string | undefined;

    do {
      const response = await this.client.send(
        new ListObjectsV2Command({
          Bucket: this.bucket,
          Prefix: prefix,
          ContinuationToken,
        }),
      );
      for (const object of response.Contents ?? []) {
        objects.push(s3ObjectToWorkspaceObject(object));
      }
      ContinuationToken = response.NextContinuationToken;
    } while (ContinuationToken);

    return objects;
  }

  async getObjectText(key: string): Promise<string | null> {
    try {
      const response = await this.client.send(
        new GetObjectCommand({ Bucket: this.bucket, Key: key }),
      );
      return (await response.Body?.transformToString()) ?? null;
    } catch (error) {
      const status = (error as { $metadata?: { httpStatusCode?: number } })
        .$metadata?.httpStatusCode;
      if (status === 404) return null;
      throw error;
    }
  }

  async copyObject(sourceKey: string, targetKey: string): Promise<void> {
    await this.client.send(
      new CopyObjectCommand({
        Bucket: this.bucket,
        CopySource: `/${this.bucket}/${encodeURIComponent(sourceKey).replace(/%2F/g, "/")}`,
        Key: targetKey,
      }),
    );
  }

  async putObject(
    key: string,
    body: string,
    contentType: string,
  ): Promise<void> {
    await this.client.send(
      new PutObjectCommand({
        Bucket: this.bucket,
        Key: key,
        Body: body,
        ContentType: contentType,
      }),
    );
  }

  async deleteObjects(keys: string[]): Promise<void> {
    if (keys.length === 0) return;
    for (let i = 0; i < keys.length; i += 1000) {
      await this.client.send(
        new DeleteObjectsCommand({
          Bucket: this.bucket,
          Delete: {
            Objects: keys.slice(i, i + 1000).map((Key) => ({ Key })),
            Quiet: true,
          },
        }),
      );
    }
  }
}

function s3ObjectToWorkspaceObject(object: _Object): WorkspaceObject {
  return {
    key: object.Key ?? "",
    etag: object.ETag ?? "",
    size: object.Size ?? 0,
    lastModified: object.LastModified?.toISOString() ?? "",
  };
}

function parseCliOptions(argv: string[]): CliOptions {
  const options: CliOptions = {
    bucket: process.env.WORKSPACE_BUCKET ?? "thinkwork-dev-storage",
    tenantSlug: "sleek-squirrel-230",
    agentSlug: "fleet-caterpillar-456",
    runId: new Date().toISOString().replace(/[:.]/g, "-"),
    apply: false,
  };

  for (let i = 0; i < argv.length; i++) {
    const arg = argv[i];
    if (arg === "--apply") {
      options.apply = true;
    } else if (arg === "--bucket") {
      options.bucket = requiredValue(argv[++i], arg);
    } else if (arg === "--tenant") {
      options.tenantSlug = requiredValue(argv[++i], arg);
    } else if (arg === "--agent") {
      options.agentSlug = requiredValue(argv[++i], arg);
    } else if (arg === "--run-id") {
      options.runId = requiredValue(argv[++i], arg);
    } else {
      throw new Error(`Unknown argument: ${arg}`);
    }
  }

  return options;
}

function requiredValue(value: string | undefined, flag: string): string {
  if (!value) throw new Error(`${flag} requires a value`);
  return value;
}

async function main(): Promise<void> {
  const options = parseCliOptions(process.argv.slice(2));
  const summary = await repairWorkspaceBlueprint({
    store: new S3WorkspaceBlueprintObjectStore({ bucket: options.bucket }),
    tenantSlug: options.tenantSlug,
    agentSlug: options.agentSlug,
    runId: options.runId,
    dryRun: !options.apply,
  });

  console.log(JSON.stringify(summary, null, 2));
}

if (import.meta.url === pathToFileURL(process.argv[1] ?? "").href) {
  main().catch((error) => {
    console.error(error);
    process.exitCode = 1;
  });
}
